/**
 * dog-routes-layer.js
 * Renders dog-friendly-routes.geojson (generated by scripts/fetch-dog-friendly-routes.js)
 * following the same fetch-based pattern as initializeWaterSources() in script.js.
 *
 * Usage: call initializeDogRoutes(trailMapInstance) inside the map 'load' handler,
 * right after initializeWaterSources(trailMapInstance).
 * Include this file in trail.html / index.html BEFORE script.js runs its map init,
 * e.g. <script src="dog-routes-layer.js"></script>
 */

function initializeDogRoutes(map) {
  // Guard against double-adding the source (same pitfall as water-sources).
  if (map.getSource('dog-routes')) return;

  fetch('./dog-friendly-routes.geojson')
    .then(response => {
      if (!response.ok) throw new Error(`HTTP ${response.status}: Failed to load dog routes GeoJSON`);
      return response.json();
    })
    .then(geojsonData => {
      console.log(`✅ Loaded ${geojsonData.features?.length || 0} dog-friendly routes`);

      map.addSource('dog-routes', { type: 'geojson', data: geojsonData });

      // Casing line (subtle white halo so routes read on top of terrain).
      // Inserted BELOW the safety-colored trail lines: this overlay is the
      // background network, and must never cover a safety rating.
      const beforeId = map.getLayer('trail-paths-line') ? 'trail-paths-line' : undefined;
      if (!map.getLayer('dog-routes-casing')) {
        map.addLayer({
          id: 'dog-routes-casing',
          type: 'line',
          source: 'dog-routes',
          layout: { 'line-join': 'round', 'line-cap': 'round' },
          paint: { 'line-color': '#ffffff', 'line-width': 4, 'line-opacity': 0.6 }
        }, beforeId);
      }

      // Main line — NEUTRAL grey-blue on purpose: green/amber/red belong
      // exclusively to the safety rating (this used to be green for loops,
      // which read as "low-risk" against the legend and contradicted the
      // trail page's own rating).
      if (!map.getLayer('dog-routes-line')) {
        map.addLayer({
          id: 'dog-routes-line',
          type: 'line',
          source: 'dog-routes',
          layout: { 'line-join': 'round', 'line-cap': 'round' },
          paint: {
            'line-color': '#7E93A3',
            'line-width': ['interpolate', ['linear'], ['zoom'], 9, 1.2, 13, 2.5],
            'line-opacity': 0.8
          }
        }, beforeId);
      }

      // One popup instance, same duplicate-popup discipline as the water markers
      let routePopup = null;

      map.on('click', 'dog-routes-line', (e) => {
        const f = e.features && e.features[0];
        if (!f) return;
        if (routePopup) { routePopup.remove(); routePopup = null; }

        const p = f.properties;
        const km = p.distance_km ? `${p.distance_km} km` : '';
        const loopBadge = (p.loop === true || p.loop === 'true')
          ? '<span style="background:#e8f5e9;color:#2e7d32;border-radius:10px;padding:1px 8px;font-size:11px;">Loop</span>'
          : '';
        const leash = p.leash && p.leash !== 'null'
          ? `<div style="font-size:12px;margin-top:4px;">🦮 Leash: ${p.leash}</div>` : '';
        const notes = p.dogFriendlyNotes && p.dogFriendlyNotes !== 'null'
          ? `<div style="font-size:12px;margin-top:4px;">${p.dogFriendlyNotes}</div>` : '';

        routePopup = new maplibregl.Popup({ offset: 10 })
          .setLngLat(e.lngLat)
          .setHTML(`
            <div style="min-width:180px;">
              <strong>${p.name || 'Unnamed route'}</strong> ${loopBadge}
              <div style="font-size:12px;color:#555;margin-top:2px;">
                ${[km, p.ref ? 'Trail ' + p.ref : ''].filter(Boolean).join(' · ')}
              </div>
              ${leash}
              ${notes}
              <div style="margin-top:6px;">
                <a href="${p.waymarkedtrails}" target="_blank" rel="noopener" style="font-size:12px;">View on Waymarked Trails ↗</a>
              </div>
            </div>
          `)
          .addTo(map);
      });

      map.on('mouseenter', 'dog-routes-line', () => { map.getCanvas().style.cursor = 'pointer'; });
      map.on('mouseleave', 'dog-routes-line', () => { map.getCanvas().style.cursor = ''; });
    })
    .catch(error => {
      console.error('❌ Error loading dog routes GeoJSON:', error.message);
    });
}
